import React, { useState } from 'react';
import { createRoot } from 'react-dom/client';
import { Button } from '../design-system/Button/Button';
import { Input } from '../design-system/Input/Input';
import { Card } from '../design-system/Card/Card';
import { Badge } from '../design-system/Badge/Badge';
import { Modal } from '../design-system/Modal/Modal';
import '../theme/variables.css';

interface IntakeData {
  first_name: string;
  last_name: string;
  dob: string | null;
  phone: string;
  address: string;
  city: string;
  province: string;
  postal_code: string;
  health_card_number: string;
  hcn_valid: boolean | null;
  allergies: string[];
  reason_for_visit: string;
  family_doctor: string;
  confidence: number;
  mock: boolean;
}

type Step = 'input' | 'review' | 'success';

const AI_SERVICE_URL = 'http://localhost:8000';

function SmartIntake() {
  const [step, setStep] = useState<Step>('input');
  const [text, setText] = useState('');
  const [parsed, setParsed] = useState<IntakeData | null>(null);
  const [edited, setEdited] = useState<Partial<IntakeData>>({});
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [showConfirm, setShowConfirm] = useState(false);

  const merge = (): IntakeData => ({ ...parsed!, ...edited });

  const handleParse = async () => {
    setError(null);
    setLoading(true);
    try {
      const res = await fetch(`${AI_SERVICE_URL}/api/v1/intake/parse`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ text }),
      });
      if (!res.ok) throw new Error(`Server error: ${res.status}`);
      const data = await res.json();
      setParsed(data);
      setEdited({});
      setStep('review');
    } catch (e: any) {
      setError(e.message || 'Failed to parse. Is the AI service running?');
    } finally {
      setLoading(false);
    }
  };

  const handleConfirm = () => {
    setShowConfirm(true);
  };

  const handleCreatePatient = () => {
    const data = merge();
    // Redirect to Oscar's form with pre-filled data
    const form = document.createElement('form');
    form.method = 'POST';
    form.action = window.location.origin + '/oscar/ws/rs/ai/intake/create';
    for (const [key, value] of Object.entries(data)) {
      if (value === null || value === undefined) continue;
      const input = document.createElement('input');
      input.type = 'hidden';
      input.name = key;
      input.value = Array.isArray(value) ? value.join(',') : String(value);
      form.appendChild(input);
    }
    document.body.appendChild(form);
    form.submit();
    setStep('success');
  };

  const handleReset = () => {
    setStep('input');
    setText('');
    setParsed(null);
    setError(null);
  };

  const updateField = (field: keyof IntakeData, value: any) => {
    setEdited(prev => ({ ...prev, [field]: value }));
  };

  const getConfidenceColor = (field: string): 'success' | 'warning' | 'error' | 'info' => {
    if (!parsed) return 'info';
    const val = merge()[field as keyof IntakeData];
    if (val && (typeof val === 'string' ? val.length > 0 : true)) return 'success';
    return 'error';
  };

  return (
    <div style={{ maxWidth: 750, margin: '0 auto', padding: 'var(--spacing-4)' }}>
      {step === 'input' && (
        <Card title="AI Smart Intake">
          <p style={{ color: 'var(--color-neutral-500)', marginBottom: 'var(--spacing-4)' }}>
            Paste or type patient details below. The AI will extract structured data automatically.
          </p>
          <textarea
            value={text}
            onChange={e => setText(e.target.value)}
            placeholder="e.g. Sarah Jones, DOB June 3 1990, 604-555-1234, 456 Oak St Vancouver V6B1A1, PHN: 9876-543-21-BC. Allergies: sulfa. Reason: annual physical"
            rows={6}
            style={{
              width: '100%', padding: 'var(--spacing-3)', fontSize: 'var(--font-size-base)',
              border: '1px solid var(--color-neutral-300)', borderRadius: 'var(--radius-md)',
              resize: 'vertical', fontFamily: 'var(--font-sans)',
            }}
            disabled={loading}
          />
          {error && (
            <div style={{ marginTop: 'var(--spacing-2)', padding: 'var(--spacing-3)', background: 'var(--color-error-light)', borderRadius: 'var(--radius-md)', color: 'var(--color-error)', fontSize: 'var(--font-size-sm)' }}>
              {error}
            </div>
          )}
          <div style={{ marginTop: 'var(--spacing-3)', display: 'flex', gap: 'var(--spacing-2)', alignItems: 'center' }}>
            <Button onClick={handleParse} disabled={text.length < 10 || loading}>
              {loading ? 'Parsing...' : 'Parse with AI'}
            </Button>
            {parsed?.mock && <Badge variant="warning">Using offline parser (AI not configured)</Badge>}
          </div>
        </Card>
      )}

      {step === 'review' && parsed && (
        <Card title="Review Extracted Data">
          {parsed.mock && (
            <div style={{ marginBottom: 'var(--spacing-3)', padding: 'var(--spacing-2)', background: 'var(--color-warning-light)', borderRadius: 'var(--radius-md)', fontSize: 'var(--font-size-sm)' }}>
              Running in mock mode. Connect an AI provider for better accuracy.
            </div>
          )}

          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 'var(--spacing-3)' }}>
            <FieldRow label="First Name" field="first_name" data={merge()} update={updateField} color={getConfidenceColor} />
            <FieldRow label="Last Name" field="last_name" data={merge()} update={updateField} color={getConfidenceColor} />
            <FieldRow label="Date of Birth" field="dob" data={merge()} update={updateField} color={getConfidenceColor} />
            <FieldRow label="Phone" field="phone" data={merge()} update={updateField} color={getConfidenceColor} />
            <FieldRow label="Address" field="address" data={merge()} update={updateField} color={getConfidenceColor} />
            <FieldRow label="City" field="city" data={merge()} update={updateField} color={getConfidenceColor} />
            <FieldRow label="Province" field="province" data={merge()} update={updateField} color={getConfidenceColor} />
            <FieldRow label="Postal Code" field="postal_code" data={merge()} update={updateField} color={getConfidenceColor} />
            <FieldRow label="Health Card" field="health_card_number" data={merge()} update={updateField} color={getConfidenceColor} />
            <div>
              <label style={{ fontSize: 'var(--font-size-xs)', color: 'var(--color-neutral-500)' }}>Allergies</label>
              <div style={{ display: 'flex', gap: 'var(--spacing-1)', flexWrap: 'wrap', marginTop: 2 }}>
                {merge().allergies.length === 0 ? <span style={{color:'var(--color-neutral-400)', fontSize:'var(--font-size-sm)'}}>None</span> : merge().allergies.map((a,i) => <Badge key={i} variant="warning">{a}</Badge>)}
              </div>
            </div>
            <FieldRow label="Reason for Visit" field="reason_for_visit" data={merge()} update={updateField} color={getConfidenceColor} />
          </div>

          <div style={{ marginTop: 'var(--spacing-4)', display: 'flex', gap: 'var(--spacing-2)', justifyContent: 'flex-end' }}>
            <Button variant="secondary" onClick={() => setStep('input')}>Back</Button>
            <Button variant="secondary" onClick={handleReset}>Reset</Button>
            <Button onClick={handleConfirm}>Create Patient</Button>
          </div>

          <Modal
            open={showConfirm}
            onClose={() => setShowConfirm(false)}
            title="Confirm Patient Creation"
            footer={
              <>
                <Button variant="secondary" onClick={() => setShowConfirm(false)}>Cancel</Button>
                <Button onClick={handleCreatePatient}>Confirm</Button>
              </>
            }
          >
            <p>Create patient record for <strong>{merge().first_name} {merge().last_name}</strong>?</p>
          </Modal>
        </Card>
      )}

      {step === 'success' && (
        <Card title="Patient Created">
          <p style={{ color: 'var(--color-success)' }}>Patient record submitted successfully.</p>
          <div style={{ marginTop: 'var(--spacing-3)' }}>
            <Button variant="secondary" onClick={handleReset}>Add Another Patient</Button>
          </div>
        </Card>
      )}
    </div>
  );
}

function FieldRow({ label, field, data, update, color }: {
  label: string; field: keyof IntakeData; data: IntakeData; update: (f: keyof IntakeData, v: string) => void; color: (f: string) => 'success' | 'warning' | 'error' | 'info';
}) {
  const value = data[field] ?? '';
  const confColor = color(field);
  return (
    <div>
      <div style={{ display: 'flex', alignItems: 'center', gap: 4, marginBottom: 2 }}>
        <label style={{ fontSize: 'var(--font-size-xs)', color: 'var(--color-neutral-500)' }}>{label}</label>
        <Badge variant={confColor}>{confColor === 'success' ? 'high' : 'low'} confidence</Badge>
      </div>
      <input
        value={typeof value === 'string' ? value : ''}
        onChange={e => update(field, e.target.value)}
        style={{
          width: '100%', padding: 'var(--spacing-1) var(--spacing-2)',
          fontSize: 'var(--font-size-sm)', border: '1px solid var(--color-neutral-300)',
          borderRadius: 'var(--radius-sm)',
        }}
      />
    </div>
  );
}

const el = document.getElementById('ai-intake-root');
if (el) createRoot(el).render(<SmartIntake />);
